26	// CanBootstrapRelay checks whether all desired target refs are absent on the target,
27	// making a bootstrap relay possible.
28	func CanBootstrapRelay(
29		force, prune bool,
30		desired map[plumbing.ReferenceName]DesiredRef,
31		targetRefs map[plumbing.ReferenceName]plumbing.Hash,
32	) (bool, string) {
33		if force || prune {
34			return false, "bootstrap-disabled-by-force-or-prune"
35		}
36		if len(desired) == 0 {
37			return false, "bootstrap-no-managed-refs"
38		}
39		for targetRef := range desired {
40			if !targetRefs[targetRef].IsZero() {
41				return false, "bootstrap-target-ref-exists"
42			}
43		}
44		return true, "empty-target-managed-refs"
45	}
46	
47	// CanIncrementalRelay checks whether all plans are eligible for the incremental
48	// relay fast-path (fast-forward branch updates + new tag creates).
49	func CanIncrementalRelay(force, prune, dryRun bool, plans []BranchPlan, target RelayTargetPolicy) (bool, string) {
50		if force || prune || dryRun {
51			return false, "incremental-disabled-by-force-prune-or-dry-run"
52		}
53		if len(plans) == 0 {
54			return false, "incremental-no-plans"
55		}
56		if !target.CapabilitiesKnown {
57			return false, "incremental-missing-target-capabilities"
58		}
59		if target.NoThin {
60			return false, "incremental-target-no-thin"
61		}
62	
63		for _, plan := range plans {
64			switch plan.Kind {
65			case RefKindBranch:
66				if !plan.SourceRef.IsBranch() || !plan.TargetRef.IsBranch() {
67					return false, "incremental-non-branch-mapping"
68				}
69				if plan.Action != ActionUpdate {
70					return false, "incremental-branch-action-not-update"
71				}
72				if plan.TargetHash.IsZero() {
73					return false, "incremental-branch-target-missing"
74				}
75			case RefKindTag:
76				if !plan.SourceRef.IsTag() || !plan.TargetRef.IsTag() {
77					return false, "incremental-non-tag-mapping"
78				}
79				if plan.Action != ActionCreate {
80					return false, "incremental-tag-action-not-create"
81				}
82			default:
83				return false, "incremental-unsupported-ref-kind"
84			}
85		}
86		return true, "fast-forward-branch-or-tag-create"
87	}
88	
89	// CanFullTagCreateRelay checks whether all plans are tag creates, eligible for
90	// a full-pack tag relay.
91	func CanFullTagCreateRelay(plans []BranchPlan) (bool, string) {
92		if len(plans) == 0 {
93			return false, "incremental-no-plans"
94		}
95		for _, plan := range plans {
96			if plan.Kind != RefKindTag {
97				return false, "incremental-tag-relay-non-tag-plan"
98			}
99			if !plan.SourceRef.IsTag() || !plan.TargetRef.IsTag() {
100				return false, "incremental-tag-relay-non-tag-mapping"
101			}
102			if plan.Action != ActionCreate {
103				return false, "incremental-tag-relay-tag-action-not-create"
104			}
105		}
106		return true, "tag-create-full-pack"
107	}
108	
109	// RelayFallbackReason returns the reason why relay was not used.
110	func RelayFallbackReason(force, prune, dryRun bool, plans []BranchPlan, target RelayTargetPolicy) string {
111		if ok, reason := CanIncrementalRelay(force, prune, dryRun, plans, target); ok {
112			return reason
113		} else if ok, reason := CanFullTagCreateRelay(plans); ok {
114			return reason
115		} else {
116			return reason
117		}
118	}
119	
120	// CanReplicateRelay checks whether replication mode can execute as a relay-only
121	// overwrite sync against the target.
122	func CanReplicateRelay(plans []BranchPlan) (bool, string) {
123		for _, plan := range plans {
124			switch plan.Kind {
125			case RefKindBranch:
126				if !plan.SourceRef.IsBranch() || !plan.TargetRef.IsBranch() {
127					return false, "replicate-non-branch-mapping"
128				}
129				if plan.Action != ActionCreate && plan.Action != ActionUpdate {
130					return false, "replicate-branch-action-not-create-or-update"
131				}
132			case RefKindTag:
133				if !plan.SourceRef.IsTag() || !plan.TargetRef.IsTag() {
134					return false, "replicate-non-tag-mapping"
135				}
136				if plan.Action != ActionCreate && plan.Action != ActionUpdate {
137					return false, "replicate-tag-action-not-create-or-update"
138				}
139			default:
140				return false, "replicate-unsupported-ref-kind"
141			}
142		}
143		return true, "replicate-overwrite-relay"
144	}
